  const res=await fetch(env.SOVV_WEB_DEPLOY_HOOK,{method:"POST"});
  await auditLog(env,{event:"sovv_web_deploy_trigger",status:res.status,success:res.ok});
  return json({ok:res.ok,status:res.status,worker:"sovv-web",triggered:res.ok});
